<div>&nbsp;&nbsp;&nbsp;&nbsp;<span style="color: #a71d5d;">for</span>(<span style="color: #066de2;">int</span>&nbsp;i<span style="color: #a71d5d;">=</span><span style="color: #0099cc;">0</span>;&nbsp;i<span style="color: #a71d5d;">&lt;</span><span style="color: #a71d5d;">=</span><span style="color: #0099cc;">4</span>;&nbsp;i<span style="color: #a71d5d;">+</span><span style="color: #a71d5d;">+</span>)</div>
