<div style="padding: 0 6px; white-space: pre; line-height: 130%;">(p&nbsp;<span style="color: #ff3399;"></span><span style="color: #a71d5d;">+</span>&nbsp;<span style="color: #0099cc;">1</span>)<span style="color: #ff3399;"></span><span style="color: #a71d5d;">-</span><span style="color: #ff3399;"></span><span style="color: #a71d5d;">&gt;</span>hab&nbsp;<span style="color: #ff3399;"></span><span style="color: #a71d5d;">=</span>&nbsp;(p&nbsp;<span style="color: #ff3399;"></span><span style="color: #a71d5d;">+</span>&nbsp;<span style="color: #0099cc;">1</span>)<span style="color: #ff3399;"></span><span style="color: #a71d5d;">-</span><span style="color: #ff3399;"></span><span style="color: #a71d5d;">&gt;</span>os&nbsp;<span style="color: #ff3399;"></span><span style="color: #a71d5d;">+</span>&nbsp;(p&nbsp;<span style="color: #ff3399;"></span><span style="color: #a71d5d;">+</span>&nbsp;<span style="color: #0099cc;">2</span>)<span style="color: #ff3399;"></span><span style="color: #a71d5d;">-</span><span style="color: #ff3399;"></span><span style="color: #a71d5d;">&gt;</span>db;</div>
